"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[732944],{103278:e=>{e.exports=JSON.parse('{"tag":{"label":"physics","permalink":"/dst-api-webdocs/docs/tags/physics","allTagsPath":"/dst-api-webdocs/docs/tags","count":104,"items":[{"id":"game-scripts/components/anchor","title":"Anchor","description":"Manages the raising and lowering state of an anchor attached to a boat, handling drag physics, animation timing, and multiplayer coordination via sailor tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/anchor"},{"id":"game-scripts/prefabs/anchor","title":"Anchor","description":"A deployable boat accessory that prevents vessel movement and interacts with water physics and environmental systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/anchor"},{"id":"game-scripts/prefabs/ancient_husks","title":"Ancient Husks","description":"Defines the prefab data and initialization logic for ancient husk statues, including identity-specific animations and physics properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancient_husks"},{"id":"game-scripts/prefabs/antlion_sinkhole","title":"Antlion Sinkhole","description":"Manages the lifecycle and damage mechanics of an antlion-triggered sinkhole, including collapse stages, repair cycles, and area-of-effect interactions with nearby entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/antlion_sinkhole"},{"id":"game-scripts/prefabs/atrium_fence","title":"Atrium Fence","description":"Controls the dynamic opening and closing behavior of an atrium fence based on player proximity and power state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/atrium_fence"},{"id":"game-scripts/prefabs/balloons_common","title":"Balloons Common","description":"Provides shared utility functions and initialization logic for balloon prefabs, including colouring, physics setup, popping behavior, and interaction with the player\'s inventory and combat systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloons_common"},{"id":"game-scripts/prefabs/balloonspeed","title":"Balloonspeed","description":"Manages the lifecycle, flight physics, and fuel-based speed progression of a floating balloon used as a consumable speed boost item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloonspeed"},{"id":"game-scripts/components/blowinwind","title":"Blowinwind","description":"Simulates wind-driven movement and speed variation for an entity by accumulating velocity in the wind direction and applying it to the locomotor component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/blowinwind"},{"id":"game-scripts/prefabs/boat","title":"Boat","description":"Manages the creation, behavior, and physics of ocean-going vessels, including variant-specific functionality (wood, grass, ice, pirate, ancient, otterden).","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat"},{"id":"game-scripts/prefabs/boat_bumper_kit","title":"Boat Bumper Kit","description":"Creates and configures deployable bumper prefabs for boats, handling health, repairs, destruction, and interaction with boat ring systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_bumper_kit"},{"id":"game-scripts/prefabs/boat_leak","title":"Boat Leak","description":"A temporary game object that simulates water leaking into a boat, interacting with nearby entities and inventory items to simulate clogging and eventual ejection.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_leak"},{"id":"game-scripts/prefabs/boat_magnet","title":"Boat Magnet","description":"A deployable structure component that enables boat magnet functionality by pairing with a beacon and responding to beacon state changes via the state graph.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_magnet"},{"id":"game-scripts/components/boatcannon","title":"Boatcannon","description":"Manages loading, aiming, and firing operations for a boat-mounted cannon, including ammo state tracking and projectile launch with recoil physics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatcannon"},{"id":"game-scripts/components/boatdrag","title":"Boatdrag","description":"Calculates and applies drag and velocity modifiers to watercraft entities during movement.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrag"},{"id":"game-scripts/components/boatdrifter","title":"Boatdrifter","description":"Manages the physics and movement state of a boat entity, including drift detection, physics activation/deactivation, and wake test lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrifter"},{"id":"game-scripts/components/boatmagnet","title":"Boatmagnet","description":"Manages the magnetic attraction behavior of a boat toward a paired beacon, calculating forces and velocity to pull the boat toward the beacon\'s location while avoiding collisions and adapting to motion.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatmagnet"},{"id":"game-scripts/components/boatphysics","title":"Boatphysics","description":"Manages boat movement, physics, steering, sail/magnet forces, drag, and collision response for watercraft entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatphysics"},{"id":"game-scripts/prefabs/boatrace_seastack","title":"Boatrace Seastack","description":"A destructible, buoyant obstacle block used in boat races that yields throwable deployment kits upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_seastack"},{"id":"game-scripts/components/boattrailmover","title":"Boattrailmover","description":"Manages movement and trajectory tracking for a boat entity in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boattrailmover"},{"id":"game-scripts/prefabs/cannonballs","title":"Cannonballs","description":"Handles the physics-based flight, target detection, and splash damage of cannonball projectiles in DST, including interaction with terrain, entities, and destructible objects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cannonballs"},{"id":"game-scripts/components/carnivalgameshooter","title":"Carnivalgameshooter","description":"Manages the aiming and shooting mechanics for the carnival shooting mini-game, controlling projectile launch parameters and aim animation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/carnivalgameshooter"},{"id":"game-scripts/prefabs/cavein_boulder","title":"Cavein Boulder","description":"Manages the state, physics, and behavior of large boulders used in cave-in events, including raised states, falling animation tracking, and formation creation upon landing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cavein_boulder"},{"id":"game-scripts/components/complexprojectile","title":"Complexprojectile","description":"Manages physics-based projectile trajectories with configurable launch conditions, gravity, and hit/miss callbacks for ranged attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/complexprojectile"},{"id":"game-scripts/prefabs/crabking_cannontower","title":"Crabking Cannontower","description":"A stationary defensive turret belonging to the Crab King that fires mortar projectiles at boats or nearby enemies and reacts to collisions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/crabking_cannontower"},{"id":"game-scripts/prefabs/daywalker2_items","title":"Daywalker2 Items","description":"Creates FX prefabs that simulate breaking and releasing loot for the Daywalker2 boss fight, including physics motion and conditional armor modification.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/daywalker2_items"},{"id":"game-scripts/components/drownable","title":"Drownable","description":"Manages drowning and void-falling logic for entities, including damage application, item dropping, and teleportation behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/drownable"},{"id":"game-scripts/components/expertsailor","title":"Expertsailor","description":"Controls configuration values that modify boat sailing physics and anchor behavior for a boat entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/expertsailor"},{"id":"game-scripts/components/explosive","title":"Explosive","description":"Manages the behavior and effects of explosive entities, including area-of-effect damage, building destruction, ignition of flammable objects, and camera effects upon detonation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/explosive"},{"id":"game-scripts/prefabs/firecrackers","title":"Firecrackers","description":"A consumable explosive item that detonates when ignited, creating a chain reaction of physical propulsion and startle effects on nearby entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firecrackers"},{"id":"game-scripts/components/fishingnetvisualizer","title":"Fishingnetvisualizer","description":"Manages visual behavior and logic for a fishing net entity during casting, opening, retrieving, and final pickup phases.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishingnetvisualizer"},{"id":"game-scripts/components/floater","title":"Floater","description":"Manages visual and behavioral effects when an entity enters or remains in water, including wetness application, splash spawning, and floating animations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/floater"},{"id":"game-scripts/prefabs/floatinglantern","title":"Floatinglantern","description":"Manages a flying lantern prefab that consumes fuel to stay airborne and emits light with dynamic physics-based behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/floatinglantern"},{"id":"game-scripts/components/freezable","title":"Freezable","description":"Manages freeze states, coldness accumulation, and thawing behavior for entities, including visual tinting, shatter effects, and resistance mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/freezable"},{"id":"game-scripts/prefabs/glass_spike","title":"Glass Spike","description":"Creates deployable glass obstacles that can be hammered into blocks and used as defensive equipment with unique visual and behavioral states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glass_spike"},{"id":"game-scripts/components/groundpounder","title":"Groundpounder","description":"Simulates a radial ground pound attack that triggers delayed damage, destruction, platform pushing, and inventory item launch effects across concentric rings.","permalink":"/dst-api-webdocs/docs/game-scripts/components/groundpounder"},{"id":"game-scripts/prefabs/halloween_ornaments","title":"Halloween Ornaments","description":"Generates prefab instances for Halloween-themed decorative inventory items with floatable physics and limited fuel value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloween_ornaments"},{"id":"game-scripts/components/heavyobstaclephysics","title":"Heavyobstaclephysics","description":"Manages dynamic physics behavior for large in-game obstacles that transition between solid, falling, and pushed states based on proximity and interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/heavyobstaclephysics"},{"id":"game-scripts/util/hitbox","title":"Hitbox","description":"Defines a configurable hitbox representation using circles and triangles, supporting world-space transformations and collision tests against points, lines, circles, triangles, and other hitboxes.","permalink":"/dst-api-webdocs/docs/game-scripts/util/hitbox"},{"id":"game-scripts/components/hullhealth","title":"Hullhealth","description":"Manages hull integrity and leak damage for boats, handling collision impacts, degradation over time, and dynamic leak indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hullhealth"},{"id":"game-scripts/prefabs/icefishing_hole","title":"Icefishing Hole","description":"Creates a stationary environmental hazard that repels players and triggers knockback upon proximity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/icefishing_hole"},{"id":"game-scripts/prefabs/inv_marble","title":"Inv Marble","description":"Represents a small, throwable marble item that acts as mole bait andquake debris.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/inv_marble"},{"id":"game-scripts/components/inventoryitem","title":"Inventoryitem","description":"Manages item properties and behavior related to inventory interaction, moisture, physics, and owner relationships.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventoryitem"},{"id":"game-scripts/components/joustsource","title":"Joustsource","description":"Manages the lance-based melee attack logic for jousting entities, including collision detection against targets within the lance\'s arc and pushback/knockback behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/joustsource"},{"id":"game-scripts/prefabs/junkball","title":"Junkball","description":"Manages the launch and fall phases of a junk projectile used in the game\'s combat and environmental mechanics, handling physics, visuals, sound, and damage application.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/junkball"},{"id":"game-scripts/map/layout","title":"Layout","description":"Provides utility functions for force-directed layout of nodes in 2D space, including repulsion from walls and points.","permalink":"/dst-api-webdocs/docs/game-scripts/map/layout"},{"id":"game-scripts/components/locomotor","title":"Locomotor","description":"Manages entity movement, pathfinding, and speed calculations, including walking, running, platform hopping, and speed modifier interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/locomotor"},{"id":"game-scripts/prefabs/malbatross_feather","title":"Malbatross Feather","description":"A lightweight, stackable item used as a cat toy and fuel source that floats on water and animates when dropped or falling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/malbatross_feather"},{"id":"game-scripts/components/mast","title":"Mast","description":"Manages sail state and forces for a boat mast, including furling/unfurling mechanics, physics interaction with the boat, and animation synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mast"},{"id":"game-scripts/prefabs/mast","title":"Mast","description":"Manages mast structures for boats, including sail deployment, fuel-powered lighting upgrades (lamp), lightning rod upgrades, and destruction behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast"},{"id":"game-scripts/prefabs/mole","title":"Mole","description":"Controls the behavior and state transitions of the mole creature, including underground/aboveground physics, inventory management, and home-seeking logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mole"},{"id":"game-scripts/prefabs/mortarball","title":"Mortarball","description":"A throwable projectile component that deals damage, triggers splash effects, and interacts with terrain and entities during flight and impact.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mortarball"},{"id":"game-scripts/prefabs/nightmarerock","title":"Nightmarerock","description":"A reactive environmental obstacle that physically rises or lowers based on nearby player sanity status, used in the sanity rock mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarerock"},{"id":"game-scripts/components/nonslipgritpool","title":"Nonslipgritpool","description":"Provides logic to determine whether a point on the ground is covered in non-slip grit, used to prevent entities from sliding on ice or slippery surfaces.","permalink":"/dst-api-webdocs/docs/game-scripts/components/nonslipgritpool"},{"id":"game-scripts/components/oar","title":"Oar","description":"Handles rowing mechanics for boats, applying directional force and managing rowing success/fail behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oar"},{"id":"game-scripts/components/oceanfishingrod","title":"Oceanfishingrod","description":"Manages the ocean fishing rod\'s casting, targeting, tension tracking, and fish capture logic, acting as the central controller for ocean fishing interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingrod"},{"id":"game-scripts/components/oceanicemanager","title":"Oceanicemanager","description":"Manages dynamic creation, damage, and destruction of ocean ice tiles in the world map, including entity interactions and visual effects.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanicemanager"},{"id":"game-scripts/prefabs/oceantree","title":"Oceantree","description":"Manages the lifecycle, growth, and interaction logic for ocean trees, including chopping, burning, converting to stumps, and transforming into ocean pillars when enriched.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantree"},{"id":"game-scripts/prefabs/oceantree_pillar","title":"Oceantree Pillar","description":"A large, water-based environmental structure that provides canopy shade, drops loot when chopped or hit, and interacts with boat collisions and lightning strikes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantree_pillar"},{"id":"game-scripts/components/oceanwhirlportalphysics","title":"Oceanwhirlportalphysics","description":"Simulates physics forces (pull and radial rotation) on entities near an ocean whirlpool portal, and handles interaction with static objects and winch targets.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanwhirlportalphysics"},{"id":"game-scripts/components/physicsmodifiedexternally","title":"Physicsmodifiedexternally","description":"Manages externally applied velocity contributions to an entity\'s physics, aggregating multiple sources and updating physics and locomotor state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/physicsmodifiedexternally"},{"id":"game-scripts/prefabs/pillar","title":"Pillar","description":"Creates and configures static environmental pillar prefabs with conditional physics, tags, and sound emitter support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pillar"},{"id":"game-scripts/prefabs/pillow_common","title":"Pillow Common","description":"Provides a shared knockback function that respects special tags and body armor defense values when applying knockback effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pillow_common"},{"id":"game-scripts/components/pinnable","title":"Pinnable","description":"Manages the pinned state and visual wear-off effect for entities that can be stuck by goo-based attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pinnable"},{"id":"game-scripts/components/platformhopdelay","title":"Platformhopdelay","description":"Manages a delay period measured in frame ticks before allowing a platform-hopping action (e.g., moving between floating platforms) to occur.","permalink":"/dst-api-webdocs/docs/game-scripts/components/platformhopdelay"},{"id":"game-scripts/prefabs/pond","title":"Pond","description":"Manages frozen, spawning, and environmental state transitions for surface and cave ponds, including seasonal freezing, child mob spawning, acid rain effects, and loot spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pond"},{"id":"game-scripts/prefabs/potatosack","title":"Potatosack","description":"Acts as a heavy, hammerable obstacle that drops loot when destroyed and can be equipped as a body item to modify movement speed and visual appearance.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/potatosack"},{"id":"game-scripts/components/projectile","title":"Projectile","description":"Handles the logic for projectiles, including trajectory, homing, collisions, and throwing behavior in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/projectile"},{"id":"game-scripts/components/pushable","title":"Pushable","description":"Enables an entity to be pushed by another entity and maintains relative positioning during the push.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pushable"},{"id":"game-scripts/prefabs/rock_ice_temperature","title":"Rock Ice Temperature","description":"Manages the dynamic stage-based growth and melting of ice boulders in response to local temperature, work, and environmental conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_ice_temperature"},{"id":"game-scripts/components/rooted","title":"Rooted","description":"Prevents an entity from moving by stopping physics and applying a speed multiplier of 0 via the locomotor component, while managing lifecycle via sources.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rooted"},{"id":"game-scripts/components/ropebridgemanager","title":"Ropebridgemanager","description":"Manages rope bridge creation, destruction, health tracking, and earthquake damage response across the world grid.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ropebridgemanager"},{"id":"game-scripts/prefabs/ruins_cavein_obstacle","title":"Ruins Cavein Obstacle","description":"Acts as a dynamic, physics-based obstacle in ruins caves that shrinks to allow character passage and falls when triggered, dealing damage or destroying nearby entities upon impact.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruins_cavein_obstacle"},{"id":"game-scripts/prefabs/seastack","title":"Seastack","description":"A breakable underwater rock entity that yields rocks when mined, serves as a collision obstacle for boats, and can be upgraded to spawn water plants; supports powder monkey tinting based on proximity to the Monkey Queen.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/seastack"},{"id":"game-scripts/stategraphs/SGalterguardian_phase4_lunarrift","title":"Sgalterguardian Phase4 Lunarrift","description":"Manages thePhase 4 lunar rift boss behavior including attack sequencing, AOE effects, camera shake, and multiple defeat/cinematic states.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGalterguardian_phase4_lunarrift"},{"id":"game-scripts/stategraphs/SGbearger","title":"Sgbearger","description":"Manages the complete behavioral stategraph for the Bearger entity, including movement, combat, attacks, staggering, yawn-based crowd control, and state transitions during special actions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGbearger"},{"id":"game-scripts/stategraphs/SGboatbumper","title":"Sgboatbumper","description":"Manages the visual states and animation lifecycle of boat bumper entities during placement, impact, and degradation.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGboatbumper"},{"id":"game-scripts/stategraphs/SGboatmagnet","title":"Sgboatmagnet","description":"Manages state transitions and animations for the boat magnet entity during beacon pairing and pulling operations.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGboatmagnet"},{"id":"game-scripts/stategraphs/SGcarnivalgame_puckdrop_station","title":"Sgcarnivalgame Puckdrop Station","description":"Defines the state machine and timeline logic for the Puck Drop carnival minigame station in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGcarnivalgame_puckdrop_station"},{"id":"game-scripts/stategraphs/SGfused_shadeling","title":"Sgfused Shadeling","description":"Manages the state machine and behavior transitions for the Fused Shadeling boss enemy, including idle movement, jumping, attacking, being hit, taunting, teleporting, and despawning.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGfused_shadeling"},{"id":"game-scripts/stategraphs/SGmalbatross","title":"Sgmalbatross","description":"State graph for the Malbatross boss, managing its flight, combat, swimming, and death behaviors via state transitions and event-driven logic.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGmalbatross"},{"id":"game-scripts/stategraphs/SGruinsnightmare","title":"Sgruinsnightmare","description":"Manages the state transitions, animations, and behavior logic for the Ruins Nightmare creature, including movement, attack phases, invisibility cycles, and despawn mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGruinsnightmare"},{"id":"game-scripts/prefabs/sharkboi_ice_hazard","title":"Sharkboi Ice Hazard","description":"Manages a dynamic, seasonally-adjusted ice boulder that melts or grows over time and can be mined for ice shards.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sharkboi_ice_hazard"},{"id":"game-scripts/components/slipperyfeet","title":"Slipperyfeet","description":"Manages the accumulation and decay of slippiness on an entity, enabling ice-related movement mechanics and slip events based on speed and environmental factors.","permalink":"/dst-api-webdocs/docs/game-scripts/components/slipperyfeet"},{"id":"game-scripts/components/slipperyfeettarget","title":"Slipperyfeettarget","description":"Marks an entity as a target location where slippery surface effects can be evaluated.","permalink":"/dst-api-webdocs/docs/game-scripts/components/slipperyfeettarget"},{"id":"game-scripts/prefabs/snowball_item","title":"Snowball Item","description":"Represents an ice-based consumable item that can be thrown, equipped, used as a water source, or built into a snowman, with melting and frost effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/snowball_item"},{"id":"game-scripts/prefabs/snowman","title":"Snowman","description":"Manages the lifecycle, growth, decoration, and destruction of a snowman entity that can be built and modified in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/snowman"},{"id":"game-scripts/prefabs/stagehand","title":"Stagehand","description":"Manages the behavior, physics state, and interactions of the Stagehand creature, including toggling between standing (active) and crouching (hiding) modes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stagehand"},{"id":"game-scripts/components/stretcher","title":"Stretcher","description":"Dynamically scales an entity along its facing axis to match the distance to a target entity, commonly used for stretchy visual effects like slingshots or elastic attachments.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stretcher"},{"id":"game-scripts/components/stuckdetection","title":"Stuckdetection","description":"Monitors an entity\'s positional movement to determine if it has become stuck for a specified duration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stuckdetection"},{"id":"game-scripts/prefabs/tumbleweed","title":"Tumbleweed","description":"A mobile environmental item that rolls in the wind and drops random loot when picked up or destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tumbleweed"},{"id":"game-scripts/prefabs/vaultcollision","title":"Vaultcollision","description":"Creates non-blocking, static collision mesh prefabs for the Vault and Lobby areas, preventing character movement through designated zones.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vaultcollision"},{"id":"game-scripts/prefabs/wagboss_robot_leg","title":"Wagboss Robot Leg","description":"Manages the landing and blocking behavior of a boss-related physics-based obstacle that reacts to environmental changes and boss presence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagboss_robot_leg"},{"id":"game-scripts/prefabs/wagpunk_arena_collision","title":"Wagpunk Arena Collision","description":"Creates non-solid physics collision boundaries for the Wagpunk arena with client-side particle effects and entity ejection logic for intruders.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagpunk_arena_collision"},{"id":"game-scripts/prefabs/wagpunk_lever","title":"Wagpunk Lever","description":"A switchablelever component that extends when activated, enabling proximity-based interaction with the Wagpunk arena manager.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagpunk_lever"},{"id":"game-scripts/components/walkableplatform","title":"Walkableplatform","description":"Manages a physical platform (e.g., a boat or raft) that players and objects can stand on, handling entity attachment, detachment, and interaction with surrounding systems like drowning, physics halting, and network registration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkableplatform"},{"id":"game-scripts/components/walkableplatformmanager","title":"Walkableplatformmanager","description":"Manages the registration, lookup, and update of walkable platforms in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkableplatformmanager"},{"id":"game-scripts/components/walkableplatformplayer","title":"Walkableplatformplayer","description":"Manages player behavior and camera integration when the player is on a walkable platform (such as a boat), including movement prediction, boat-based camera effects, and zoom handling.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkableplatformplayer"},{"id":"game-scripts/prefabs/walls","title":"Walls","description":"Provides the underlying component logic andprefab factory for generating wall entities with health, pathfinding, and construction mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/walls"},{"id":"game-scripts/components/waterphysics","title":"Waterphysics","description":"Applies basic physical properties to entities that interact with water, specifically defining their bounciness (restitution).","permalink":"/dst-api-webdocs/docs/game-scripts/components/waterphysics"},{"id":"game-scripts/prefabs/waterprojectiles","title":"Waterprojectiles","description":"Defines prefabs and behaviors for water-based projectiles (snowballs, water balloons, ink splats, bile splats, and water streaks), each implementing custom collision handling, projectile physics, and fire suppression or status effects via the wateryprotection and complexprojectile components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterprojectiles"},{"id":"game-scripts/prefabs/watertree_pillar","title":"Watertree Pillar","description":"Acts as a large ocean-dwelling structure that periodically spawns grassgators, drops items when rammed by boats, blocks lightning, and manages canopy effects for nearby players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/watertree_pillar"},{"id":"game-scripts/prefabs/wave","title":"Wave","description":"Simulates an ocean wave entity that moves, interacts with boats and items, and triggers splash effects upon collision or contact with land.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wave"},{"id":"game-scripts/prefabs/winch","title":"Winch","description":"Manages the mechanical winch structure that can lower and raise a claw to salvage submerged objects, while interacting with boat physics and inventory systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winch"},{"id":"game-scripts/prefabs/world","title":"World","description":"Manages the global world instance and initial setup for the game environment, including map rendering, tile physics, components, and prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/world"}],"unlisted":false}}')}}]);